	"github.com/stretchr/testify/assert"
)

func TestNodeNameFallbackLowercaseHostname(t *testing.T) {
	// Verify that when NodeName is not set, the fallback hostname is lowercased
	// to ensure RFC 1123 compliance (node names must be lowercase).

	// Get the actual hostname
	hostname, err := os.Hostname()
	assert.NoError(t, err, "should be able to get hostname")

	config := &kubevip.Config{
		NodeName: "", // Empty, so it should fall back to hostname
	}

	// We can't easily mock os.Hostname(), so we test the behavior indirectly:
	// if the hostname has uppercase characters, the config.NodeName should be
	// lowercased after New() is called.
	// Since New() requires k8s clients, we test the logic directly by checking
	// what would happen with an uppercase hostname.

	// Simulate the fallback logic (the fix should lowercase the hostname)
	fallbackName := strings.ToLower(hostname)

	t.Logf("Hostname: %s, Lowercased: %s", hostname, fallbackName)

	// Verify that the lowercased version has no uppercase characters
	assert.Equal(t, strings.ToLower(fallbackName), fallbackName,
		"lowercased hostname should not contain any uppercase characters")

	// Verify it's RFC 1123 compliant: must be lowercase alphanumeric plus '-' and '.'
	for _, ch := range fallbackName {
		isValid := (ch >= 'a' && ch <= 'z') || (ch >= '0' && ch <= '9') || ch == '-' || ch == '.'
		assert.True(t, isValid,
			"character '%c' in lowercased hostname '%s' should be RFC 1123 compliant", ch, fallbackName)
	}
}

